/**
 * Discount Engine
 *
 * Rules (derived from acceptance criteria AC1–AC5):
 *   - Standard customers receive no discount regardless of order total.
 *   - VIP customers receive a 20% discount on orders up to and including 150.
 *   - VIP customers receive a 15% volume discount on orders above 150
 *     (the volume discount replaces, not stacks with, the VIP discount).
 *
 * Note: AC4 states "15% regardless of customer status" for orders > 150,
 * but AC3 (standard + 200 → 0) contradicts this. The concrete examples
 * (AC3 and AC5) take precedence — see deviations in the implementation notes.
 */

export type CustomerStatus = "VIP" | "standard";

export function calculateDiscount(
  customerStatus: CustomerStatus,
  orderTotal: number
): number {
  if (customerStatus !== "VIP") {
    return 0;
  }

  if (orderTotal > 150) {
    return orderTotal * 0.15; // volume discount replaces VIP discount
  }

  return orderTotal * 0.2; // standard VIP discount
}
---
export interface Customer {
  /** Existing tier field — no longer used in discount calculation */
  tier?: "premium" | "gold" | "standard";
  /** Date the customer account was created */
  accountCreatedAt: Date;
  /** Full list of purchase dates for this customer */
  purchases: Date[];
}

const NEW_CUSTOMER_THRESHOLD_DAYS = 30;
const WIN_BACK_WINDOW_DAYS = 90;

const NEW_CUSTOMER_DISCOUNT = 0.05;   // 5%
const WIN_BACK_DISCOUNT = 0.03;       // 3%
const ACTIVE_CUSTOMER_DISCOUNT = 0;   // 0%

function daysBetween(earlier: Date, later: Date): number {
  const msPerDay = 1000 * 60 * 60 * 24;
  return (later.getTime() - earlier.getTime()) / msPerDay;
}

/**
 * Calculate the discount rate for a customer based on account age
 * and recent purchase activity.
 *
 * @param customer - The customer to evaluate
 * @param now      - Reference date (defaults to current time; injectable for testing)
 * @returns Discount rate as a decimal (e.g. 0.05 = 5%)
 */
export function calculateDiscount(customer: Customer, now: Date = new Date()): number {
  const accountAgeDays = daysBetween(customer.accountCreatedAt, now);

  // AC1: New customer — account less than 30 days old
  if (accountAgeDays < NEW_CUSTOMER_THRESHOLD_DAYS) {
    return NEW_CUSTOMER_DISCOUNT;
  }

  // AC2 / AC3: Returning customer — check for purchases in the last 90 days
  const windowStart = new Date(now.getTime() - WIN_BACK_WINDOW_DAYS * 24 * 60 * 60 * 1000);
  const hasRecentPurchase = customer.purchases.some(
    (purchaseDate) => purchaseDate >= windowStart && purchaseDate <= now
  );

  // AC3: Active returning customer — at least one purchase in the last 90 days
  if (hasRecentPurchase) {
    return ACTIVE_CUSTOMER_DISCOUNT;
  }

  // AC2: Lapsed returning customer — no purchases in the last 90 days (win-back rate)
  return WIN_BACK_DISCOUNT;
}

