import { calculateDiscount } from "./discountEngine";

describe("calculateDiscount", () => {
  // AC1: VIP + 100 → 20 (20%)
  it("AC1: gives a VIP customer 20% off an order of 100", () => {
    expect(calculateDiscount("VIP", 100)).toBe(20);
  });

  // AC2: VIP + 50 → 10 (20%)
  it("AC2: gives a VIP customer 20% off an order of 50", () => {
    expect(calculateDiscount("VIP", 50)).toBe(10);
  });

  // AC3: standard + 200 → 0
  it("AC3: gives a standard customer no discount regardless of order total", () => {
    expect(calculateDiscount("standard", 200)).toBe(0);
  });

  // AC4 (partial): order > 150 → 15% for VIP
  it("AC4: applies 15% volume discount for orders above 150 (VIP)", () => {
    expect(calculateDiscount("VIP", 151)).toBeCloseTo(151 * 0.15);
  });

  // AC5: VIP + 200 → 30 (15% volume discount)
  it("AC5: gives a VIP customer 15% volume discount on an order of 200", () => {
    expect(calculateDiscount("VIP", 200)).toBe(30);
  });

  // Edge: standard customer with large order still gets 0
  it("standard customer with order > 150 still gets 0 discount", () => {
    expect(calculateDiscount("standard", 500)).toBe(0);
  });

  // Edge: VIP at the boundary (exactly 150) gets 20%
  it("VIP customer at exactly 150 gets 20% discount (30)", () => {
    expect(calculateDiscount("VIP", 150)).toBe(30);
  });

  // Edge: VIP just above boundary (151) gets 15%
  it("VIP customer just above 150 gets 15% volume discount", () => {
    expect(calculateDiscount("VIP", 151)).toBeCloseTo(22.65);
  });
});

